// app/page.tsx
"use client";

import { useStorage, useMutation, useOthers, useUpdateMyPresence, useSelf } from "@liveblocks/react";
import { useEffect, useMemo } from "react";

type FieldId = "name" | "email" | "bio";

const FIELD_LABELS: Record<FieldId, string> = {
  name: "Name",
  email: "Email",
  bio: "Bio",
};

export default function Page() {
  const form = useStorage((root) => root.form);
  const updateMyPresence = useUpdateMyPresence();
  const others = useOthers();

  // Get display name from URL
  const displayName = useMemo(() => {
    if (typeof window === "undefined") return "Anonymous";
    const params = new URLSearchParams(window.location.search);
    return params.get("name") || "Anonymous";
  }, []);

  // Update presence with display name
  useEffect(() => {
    updateMyPresence({ info: { name: displayName } });
  }, [displayName, updateMyPresence]);

  // Mutation to update form field
  const updateField = useMutation(({ storage }, field: FieldId, value: string) => {
    storage.get("form").set(field, value);
  }, []);
);

  // Compute which other users are typing in each field
  const typingUsersByField = useMemo(() => {
    const result: Record<FieldId, Array<{ name: string }>> = { name: [], email: [], bio: [] };
    for (const other of others) {
      const typing = other.presence?.typing;
      if (typing && typing in result) {
        result[typing as FieldId].push({ name: other.presence?.info?.name || "Anonymous" });
      }
    }
    return result;
  }, [others]);

  return (
    <main>
      <h1>Multiplayer Form</h1>
      <p>Collaborate with other users in real time.</p>

      {(["name", "email", "bio"] as FieldId[]).map((field) => {
        const isTypingByOther = typingUsersByField[field].length > 0;
        const typingIndicatorText = typingUsersByField[field]
          .map((u) => u.name)
          .join(", ");
        const label = FIELD_LABELS[field];

        return (
          <div key={field} style={{ marginTop: field === "name" ? 24 : 16 }}>
            <label htmlFor={field}>{label}</label>
            {typingUsersByField[field].length > 0 && (
              <div data-testid={`typing-indicator-${field}`}>
                {typingUsersByField[field].map((u) => u.name).join(", ")} is typing in {label}...
              </div>
            )}
            <div style={{ position: "relative" }}>
              {field === "bio" ? (
                <textarea
                  id={field}
                  data-testid={`input-${field}`}
                  value={form?.bio ?? ""}
                  onChange={(e) => updateField("bio", e.target.value)}
                  onFocus={() => updateMyPresence({ typing: "bio" })}
                  onBlur={() => updateMyPresence({ typing: null })}
                  rows={4}
                  style={{ display: "block", width: "100%", padding: 8 }}
                />
              ) : (
                <input
                  id={field}
                  data-testid={`input-${field}`}
                  type={field === "email" ? "email" : "text"}
                  value={form?.[field] ?? ""}
                  onChange={(e) => updateField(field, e.target.value)}
                  onFocus={() => updateMyPresence({ typing: field })}
                  onBlur={() => updateMyPresence({ typing: null })}
                  style={{ display: "block", width: "100%", padding: 8 }}
                />
              )}
              {isTypingByOther && (
                <div
                  data-testid={`lock-overlay-${field}`}
                  style={{
                    position: "absolute",
                    top: 0,
                    left: 0,
                    right: 0,
                    bottom: 0,
                    backgroundColor: "rgba(200, 200, 200, 0.5)",
                    pointerEvents: "none",
                    borderRadius: 4,
                  }}
                />
              )}
            </div>
          </div>
        );
      })}
    </main>
  );
}
